#include <iostream>
using namespace std;

// Base class
class Animal {
public:
    // Virtual function for runtime polymorphism
    virtual void sound() {
        cout << "Animal makes a sound" << endl;
    }

    // Virtual destructor (important for proper cleanup)
    virtual ~Animal() {
        cout << "Animal destructor called" << endl;
    }
};

// Derived class - Dog
class Dog : public Animal {
public:
    void sound() override {
        cout << "Dog barks: Woof! Woof!" << endl;
    }

    ~Dog() {
        cout << "Dog destructor called" << endl;
    }
};

// Derived class - Cat
class Cat : public Animal {
public:
    void sound() override {
        cout << "Cat meows: Meow! Meow!" << endl;
    }

    ~Cat() {
        cout << "Cat destructor called" << endl;
    }
};

int main() {
    // Base class pointer pointing to derived class objects
    Animal* animal1 = new Dog();
    Animal* animal2 = new Cat();

    // Runtime polymorphism - which version of sound() to call?
    // Decided at runtime based on actual object type
    animal1->sound();  // Calls Dog's version
    animal2->sound();  // Calls Cat's version

    // Proper cleanup with virtual destructor
    delete animal1;
    delete animal2;

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

// Shape - Abstract base class with pure virtual function
class Shape {
protected:
    string color;
public:
    Shape(string c) : color(c) {}

    // Pure virtual function - makes Shape abstract
    virtual double area() const = 0;
    virtual void display() const = 0;

    virtual ~Shape() {}
};

// Rectangle class
class Rectangle : public Shape {
private:
    double width, height;
public:
    Rectangle(double w, double h, string c) : Shape(c), width(w), height(h) {}

    double area() const override {
        return width * height;
    }

    void display() const override {
        cout << "Rectangle - Color: " << color 
             << ", Area: " << area() << endl;
    }
};

// Circle class
class Circle : public Shape {
private:
    double radius;
public:
    Circle(double r, string c) : Shape(c), radius(r) {}

    double area() const override {
        return 3.14159 * radius * radius;
    }

    void display() const override {
        cout << "Circle - Color: " << color 
             << ", Area: " << area() << endl;
    }
};

// Triangle class
class Triangle : public Shape {
private:
    double base, height;
public:
    Triangle(double b, double h, string c) : Shape(c), base(b), height(h) {}

    double area() const override {
        return 0.5 * base * height;
    }

    void display() const override {
        cout << "Triangle - Color: " << color 
             << ", Area: " << area() << endl;
    }
};

int main() {
    // Array of base class pointers - runtime polymorphism in action
    Shape* shapes[3];

    // Storing different derived objects in base pointer array
    shapes[0] = new Rectangle(5.0, 3.0, "Red");
    shapes[1] = new Circle(2.5, "Blue");
    shapes[2] = new Triangle(4.0, 6.0, "Green");

    cout << "=== Polymorphic Output ===" << endl;

    // Same method call, different behaviors based on actual object type
    for (int i = 0; i < 3; i++) {
        shapes[i]->display();  // Runtime decides which display() to call
    }

    // Calculate total area using polymorphism
    double totalArea = 0;
    for (int i = 0; i < 3; i++) {
        totalArea += shapes[i]->area();
    }
    cout << "Total Area: " << totalArea << endl;

    // Cleanup
    for (int i = 0; i < 3; i++) {
        delete shapes[i];
    }

    return 0;
}

#include <iostream>
#include <typeinfo>
using namespace std;

// Base class
class Employee {
protected:
    string name;
    int id;
    double salary;
public:
    Employee(string n, int i, double s) : name(n), id(i), salary(s) {}

    virtual void calculateBonus() {
        cout << name << ": Base bonus = Rs. " << salary * 0.1 << endl;
    }

    virtual void display() {
        cout << "ID: " << id << ", Name: " << name 
             << ", Salary: Rs. " << salary << endl;
    }

    // Getter for salary
    double getSalary() const { return salary; }

    virtual ~Employee() {}
};

// Derived: Manager
class Manager : public Employee {
private:
    int teamSize;
public:
    Manager(string n, int i, double s, int ts) 
        : Employee(n, i, s), teamSize(ts) {}

    void calculateBonus() override {
        double bonus = salary * 0.15 + (teamSize * 100);
        cout << name << ": Manager bonus = Rs. " << bonus << endl;
    }

    void display() override {
        cout << "[Manager] ";
        Employee::display();
        cout << "Team Size: " << teamSize << endl;
    }
};

// Derived: Developer
class Developer : public Employee {
private:
    string programmingLang;
public:
    Developer(string n, int i, double s, string lang) 
        : Employee(n, i, s), programmingLang(lang) {}

    void calculateBonus() override {
        double bonus = salary * 0.12;
        cout << name << ": Developer bonus = Rs. " << bonus << endl;
    }

    void display() override {
        cout << "[Developer] ";
        Employee::display();
        cout << "Language: " << programmingLang << endl;
    }
};

// Function demonstrating polymorphism - accepts base class pointer
void processEmployee(Employee* emp) {
    cout << "\n--- Processing Employee ---" << endl;
    emp->display();
    emp->calculateBonus();

    // RTTI - Runtime Type Identification
    cout << "Type: " << typeid(*emp).name() << endl;

    // Using dynamic_cast for safe downcasting
    Manager* mgr = dynamic_cast<Manager*>(emp);
    if (mgr) {
        cout << "This is a Manager with team leadership responsibilities!" << endl;
    }

    Developer* dev = dynamic_cast<Developer*>(emp);
    if (dev) {
        cout << "This is a Developer with coding expertise!" << endl;
    }
}

int main() {
    // Create objects on heap
    Employee* employees[3];

    employees[0] = new Employee("John Smith", 101, 50000);
    employees[1] = new Manager("Alice Johnson", 102, 80000, 10);
    employees[2] = new Developer("Bob Williams", 103, 60000, "C++");

    // Process each employee polymorphically
    for (int i = 0; i < 3; i++) {
        processEmployee(employees[i]);
    }

    // Demonstrate pointer arithmetic and virtual function table
    cout << "\n=== Using Base Pointer Array Directly ===" << endl;
    for (int i = 0; i < 3; i++) {
        employees[i]->calculateBonus();
    }

    // Cleanup
    for (int i = 0; i < 3; i++) {
        delete employees[i];
    }

    return 0;
}
